#include <stdio.h>
#include <limits.h>
int main() {
    int N, M, D;
    scanf("%d %d %d", &N, &M, &D);
    long long dp[N][M];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            dp[i][j] = 0;
        }
    }
    long long rates[N][2*M];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < 2*M; j++) {
            scanf("%lld", &rates[i][j]);
        }
    }
    for (int i = 0; i < N; i++) {
        dp[i][0] = D;
    }
    for (int j = 1; j < M; j++) {
        for (int i = 0; i < N; i++) {
            long long max = 0;
            for (int k = 0; k < N; k++) {
                if (k != i) {
                    long long temp = dp[k][j-1] * rates[k][2*(j-1)+1] / rates[i][2*j];
                    if (temp > max) {
                        max = temp;
                    }
                }
            }
            dp[i][j] = max;
        }
    }
    long long ans = 0;
    for (int i = 0; i < N; i++) {
        if (dp[i][M-1] > ans) {
            ans = dp[i][M-1];
        }
    }
    printf("%lld\n", ans);
    return 0;
}

