                rates[i][j] = sc.nextLong();
            }
        }
        for (int i = 0; i < N; i++) {
            dp[i][0] = D;
        }
        for (int j = 1; j < M; j++) {
            for (int i = 0; i < N; i++) {
                long max = 0;
                for (int k = 0; k < N; k++) {
                    if (k != i) {
                        long temp = dp[k][j-1] * rates[k][2*(j-1)+1] / rates[i][2*j];
                        if (temp > max) {
                            max = temp;
                        }
                    }
                }
                dp[i][j] = max;
            }
        }
        long ans = 0;
